fn create_rate_limiter(api_key: &str) -> impl Fn(String) -> bool {
    let context = format!("{}:{}", api_key, "default_ttl");
    move |request_id: String| {
        println!("Checking rate limit for request {} using context {}", request_id, context);
        if request_id.starts_with("fail") {
            false
        } else {
            true
        }
    }
}

